INSERT INTO `pnd_politicas` (`id`, `pnd_id`, `codigo`, `nombre`, `descripcion`, `estado`, `created_at`, `updated_at`) VALUES
	(1, 1, '1.1', 'Contribuir a la reducción de la pobreza y pobreza extrema', 'Contribuir a la reducción de la pobreza y pobreza extrema.', 'Activo', '2026-07-16 12:35:32', '2026-07-16 12:35:32'),
	(2, 1, '1.2', 'Garantizar la inclusión social de las personas y grupos de atención prioritaria durante su ciclo de vida', 'Garantizar la inclusión social de las personas y grupos de atención prioritaria durante su ciclo de vida.', 'Activo', '2026-07-16 12:35:32', '2026-07-16 12:35:32'),
	(3, 1, '1.3', 'Fortalecer el acceso oportuno, equitativo y de calidad a los servicios integrales de salud', 'Fortalecer el acceso oportuno, equitativo y de calidad a los servicios integrales de salud.', 'Activo', '2026-07-16 12:35:32', '2026-07-16 12:35:32'),
	(4, 1, '1.4', 'Promover la prevención y el control integral de enfermedades', 'Promover la prevención y el control integral de enfermedades mediante acciones de promoción de la salud y prevención de riesgos.', 'Activo', '2026-07-16 12:35:32', '2026-07-16 12:35:32'),
	(5, 1, '1.5', 'Fortalecer la atención integral durante todo el ciclo de vida', 'Fortalecer la atención integral de la población durante todo el ciclo de vida con enfoque de derechos e interculturalidad.', 'Activo', '2026-07-16 12:35:32', '2026-07-16 12:35:32'),
	(6, 1, '1.6', 'Garantizar el acceso a medicamentos, vacunas e insumos estratégicos', 'Garantizar el acceso oportuno a medicamentos, vacunas e insumos estratégicos para la población.', 'Activo', '2026-07-16 12:35:32', '2026-07-16 12:35:32'),
	(7, 1, '1.7', 'Promover el acceso a vivienda digna y adecuada', 'Promover el acceso a vivienda digna, adecuada y con servicios básicos.', 'Activo', '2026-07-16 12:35:32', '2026-07-16 12:35:32'),
	(8, 1, '1.8', 'Fortalecer los mecanismos de protección social', 'Fortalecer los mecanismos de protección social para la población en situación de vulnerabilidad.', 'Activo', '2026-07-16 12:35:32', '2026-07-16 12:35:32'),
	(9, 1, '1.9', 'Impulsar la igualdad de oportunidades y la no discriminación', 'Impulsar la igualdad de oportunidades y la eliminación de toda forma de discriminación.', 'Activo', '2026-07-16 12:35:32', '2026-07-16 12:35:32'),
	(10, 1, '1.10', 'Fortalecer la atención integral a grupos prioritarios', 'Fortalecer la atención integral a grupos de atención prioritaria.', 'Activo', '2026-07-16 12:35:32', '2026-07-16 12:35:32'),
	(11, 1, '1.11', 'Promover entornos saludables y seguros', 'Promover entornos saludables y seguros para mejorar la calidad de vida de la población.', 'Activo', '2026-07-16 12:35:32', '2026-07-16 12:35:32'),
	(12, 1, '1.12', 'Fortalecer la articulación interinstitucional para el bienestar social', 'Fortalecer la articulación interinstitucional para mejorar el bienestar social y reducir las desigualdades.', 'Activo', '2026-07-16 12:35:32', '2026-07-16 12:35:32'),
	(13, 2, '2.1', 'Garantizar el acceso universal a una educación inclusiva, equitativa, pertinente e intercultural', 'Garantizar el acceso universal a una educación inclusiva, equitativa, pertinente e intercultural para niños, niñas, adolescentes, jóvenes y adultos, promoviendo la permanencia y culminación de sus estudios; y asegurando su movilidad dentro del Sistema Nacional de Educación.', 'Activo', '2026-07-16 12:35:45', '2026-07-16 12:35:45'),
	(14, 2, '2.2', 'Fortalecer la calidad del Sistema Nacional de Educación', 'Fortalecer la calidad del Sistema Nacional de Educación mediante el mejoramiento de los procesos de enseñanza y aprendizaje, el fortalecimiento de las competencias docentes, la innovación pedagógica y la evaluación permanente.', 'Activo', '2026-07-16 12:35:45', '2026-07-16 12:35:45'),
	(15, 2, '2.3', 'Fortalecer el acceso, permanencia y titulación en la educación superior', 'Fortalecer el acceso, permanencia y titulación en la educación superior, garantizando igualdad de oportunidades, calidad, pertinencia e inclusión.', 'Activo', '2026-07-16 12:35:45', '2026-07-16 12:35:45'),
	(16, 2, '2.4', 'Impulsar la investigación, el desarrollo científico, tecnológico y la innovación', 'Impulsar la investigación, el desarrollo científico, tecnológico, la innovación y la transferencia del conocimiento para contribuir al desarrollo nacional.', 'Activo', '2026-07-16 12:35:45', '2026-07-16 12:35:45'),
	(17, 2, '2.5', 'Promover el acceso, la participación y el fortalecimiento de la cultura y el patrimonio', 'Promover el acceso, la participación ciudadana, la protección del patrimonio cultural y el fortalecimiento de la identidad nacional, la interculturalidad y las expresiones artísticas.', 'Activo', '2026-07-16 12:35:45', '2026-07-16 12:35:45'),
	(18, 3, '3.1', 'Prever, prevenir y controlar los fenómenos de violencia y delincuencia', 'Prever, prevenir y controlar, con pertinencia territorial, los fenómenos de violencia y delincuencia que afectan a la ciudadanía y sus derechos, fortaleciendo la convivencia pacífica.', 'Activo', '2026-07-16 12:35:53', '2026-07-16 12:35:53'),
	(19, 3, '3.2', 'Contrarrestar las economías criminales', 'Contrarrestar las economías criminales, fortaleciendo las acciones de investigación, persecución y control de la delincuencia organizada, el narcotráfico, la minería ilegal, el control migratorio, apoyando a la consolidación y sostenibilidad del sistema económico.', 'Activo', '2026-07-16 12:35:53', '2026-07-16 12:35:53'),
	(20, 3, '3.3', 'Fortalecer el sistema nacional de rehabilitación social', 'Fortalecer el Sistema Nacional de Rehabilitación Social mediante acciones integrales que contribuyan a la seguridad ciudadana, la reinserción social y la reducción de la reincidencia delictiva.', 'Activo', '2026-07-16 12:35:53', '2026-07-16 12:35:53'),
	(21, 3, '3.4', 'Fortalecer el sistema de justicia', 'Fortalecer el sistema de justicia para garantizar el acceso oportuno, eficiente, transparente e independiente, con respeto a los derechos humanos.', 'Activo', '2026-07-16 12:35:53', '2026-07-16 12:35:53'),
	(22, 3, '3.5', 'Fortalecer la protección integral de víctimas y testigos', 'Fortalecer los mecanismos de protección integral de víctimas, testigos y demás personas que intervienen en los procesos judiciales, garantizando el ejercicio de sus derechos.', 'Activo', '2026-07-16 12:35:53', '2026-07-16 12:35:53'),
	(23, 3, '3.6', 'Fortalecer la seguridad integral en las zonas de frontera', 'Fortalecer la seguridad integral en las zonas de frontera mediante acciones coordinadas entre las instituciones del Estado para prevenir y combatir las amenazas transnacionales.', 'Activo', '2026-07-16 12:36:00', '2026-07-16 12:36:00'),
	(24, 3, '3.7', 'Fortalecer la gestión integral de riesgos para la seguridad ciudadana', 'Fortalecer la gestión integral de riesgos y las capacidades institucionales para prevenir y responder oportunamente a eventos que afecten la seguridad de la población.', 'Activo', '2026-07-16 12:36:00', '2026-07-16 12:36:00'),
	(25, 3, '3.8', 'Fortalecer las capacidades operativas de las instituciones de seguridad', 'Fortalecer las capacidades operativas, tecnológicas y logísticas de las instituciones responsables de la seguridad ciudadana y el orden público.', 'Activo', '2026-07-16 12:36:00', '2026-07-16 12:36:00'),
	(26, 3, '3.9', 'Impulsar la cooperación nacional e internacional en materia de seguridad', 'Impulsar mecanismos de cooperación nacional e internacional para enfrentar la delincuencia organizada, el crimen transnacional y otras amenazas a la seguridad.', 'Activo', '2026-07-16 12:36:00', '2026-07-16 12:36:00'),
	(27, 3, '3.10', 'Promover una cultura de paz y convivencia ciudadana', 'Promover una cultura de paz, prevención de la violencia, resolución pacífica de conflictos y convivencia ciudadana con enfoque de derechos humanos.', 'Activo', '2026-07-16 12:36:00', '2026-07-16 12:36:00'),
	(28, 3, '3.11', 'Fortalecer la ciberseguridad y la protección de la información', 'Fortalecer las capacidades nacionales de ciberseguridad para proteger la información, las infraestructuras críticas y los servicios digitales del Estado.', 'Activo', '2026-07-16 12:36:21', '2026-07-16 12:36:21'),
	(29, 3, '3.12', 'Promover la prevención de la violencia desde el ámbito comunitario', 'Promover acciones integrales de prevención de la violencia mediante la participación ciudadana, la corresponsabilidad social y el fortalecimiento del tejido comunitario.', 'Activo', '2026-07-16 12:36:21', '2026-07-16 12:36:21'),
	(30, 3, '3.13', 'Fortalecer la lucha contra la corrupción y la impunidad', 'Fortalecer los mecanismos institucionales para prevenir, investigar y sancionar los actos de corrupción e impunidad en todos los niveles del Estado.', 'Activo', '2026-07-16 12:36:21', '2026-07-16 12:36:21'),
	(31, 3, '3.14', 'Fortalecer la transparencia y la confianza ciudadana en las instituciones', 'Fortalecer la transparencia, la rendición de cuentas y la confianza de la ciudadanía en las instituciones públicas relacionadas con la seguridad y la justicia.', 'Activo', '2026-07-16 12:36:21', '2026-07-16 12:36:21'),
	(32, 3, '3.15', 'Impulsar la modernización tecnológica de los organismos de seguridad y justicia', 'Impulsar la modernización tecnológica y la transformación digital de los organismos responsables de la seguridad y la administración de justicia.', 'Activo', '2026-07-16 12:36:21', '2026-07-16 12:36:21'),
	(33, 3, '3.16', 'Fortalecer la coordinación interinstitucional para la seguridad integral', 'Fortalecer la coordinación entre las instituciones competentes para mejorar la planificación, ejecución y evaluación de las políticas de seguridad integral.', 'Activo', '2026-07-16 12:36:21', '2026-07-16 12:36:21'),
	(34, 3, '3.17', 'Consolidar un sistema integral de seguridad ciudadana', 'Consolidar un sistema integral de seguridad ciudadana basado en la prevención, la protección de derechos, la participación ciudadana y la respuesta oportuna frente a las amenazas.', 'Activo', '2026-07-16 12:36:21', '2026-07-16 12:36:21'),
	(35, 4, '4.1', 'Impulsar el crecimiento económico sostenible', 'Impulsar un crecimiento económico sostenible mediante el fortalecimiento de la producción nacional, la inversión y el incremento de la productividad.', 'Activo', '2026-07-16 12:36:30', '2026-07-16 12:36:30'),
	(36, 4, '4.2', 'Fortalecer el desarrollo productivo nacional', 'Fortalecer el desarrollo productivo nacional promoviendo la diversificación económica, la innovación y la generación de valor agregado.', 'Activo', '2026-07-16 12:36:30', '2026-07-16 12:36:30'),
	(37, 4, '4.3', 'Promover la competitividad de los sectores productivos', 'Promover la competitividad de los sectores productivos mediante el acceso a financiamiento, innovación, asistencia técnica y apertura de mercados.', 'Activo', '2026-07-16 12:36:30', '2026-07-16 12:36:30'),
	(38, 4, '4.4', 'Impulsar la industrialización y la transformación productiva', 'Impulsar procesos de industrialización, transformación productiva y sustitución estratégica de importaciones para fortalecer la economía nacional.', 'Activo', '2026-07-16 12:36:30', '2026-07-16 12:36:30'),
	(39, 4, '4.5', 'Fortalecer el desarrollo rural y agroproductivo', 'Fortalecer el desarrollo rural y agroproductivo mediante el incremento de la productividad, la asistencia técnica y el acceso a mercados.', 'Activo', '2026-07-16 12:36:30', '2026-07-16 12:36:30'),
	(40, 4, '4.6', 'Promover la inversión nacional y extranjera', 'Promover la inversión nacional y extranjera mediante un entorno favorable para el desarrollo productivo y la generación de empleo.', 'Activo', '2026-07-16 12:36:30', '2026-07-16 12:36:30'),
	(41, 4, '4.7', 'Fortalecer la integración comercial y el acceso a mercados internacionales', 'Fortalecer la integración comercial y ampliar el acceso de los productos ecuatorianos a los mercados nacionales e internacionales.', 'Activo', '2026-07-16 12:36:30', '2026-07-16 12:36:30'),
	(42, 5, '5.1', 'Promover la generación de empleo digno', 'Promover la generación de empleo digno, adecuado y sostenible mediante el fortalecimiento de los sectores productivos y la inversión.', 'Activo', '2026-07-16 12:36:38', '2026-07-16 12:36:38'),
	(43, 5, '5.2', 'Fortalecer la economía popular y solidaria', 'Fortalecer la economía popular y solidaria, promoviendo la asociatividad, el emprendimiento y el acceso a mercados.', 'Activo', '2026-07-16 12:36:38', '2026-07-16 12:36:38'),
	(44, 5, '5.3', 'Impulsar el emprendimiento y la innovación empresarial', 'Impulsar el emprendimiento, la innovación empresarial y el desarrollo de nuevos modelos de negocio para dinamizar la economía nacional.', 'Activo', '2026-07-16 12:36:38', '2026-07-16 12:36:38'),
	(45, 5, '5.4', 'Fortalecer las capacidades para el empleo', 'Fortalecer las capacidades técnicas y profesionales de la población para mejorar la empleabilidad y responder a las necesidades del mercado laboral.', 'Activo', '2026-07-16 12:36:38', '2026-07-16 12:36:38'),
	(46, 5, '5.5', 'Promover la formalización laboral', 'Promover la formalización del empleo y el cumplimiento de los derechos laborales mediante mecanismos de incentivo y control.', 'Activo', '2026-07-16 12:36:38', '2026-07-16 12:36:38'),
	(47, 5, '5.6', 'Reducir las brechas de acceso al empleo', 'Reducir las brechas de acceso al empleo para mujeres, jóvenes, personas con discapacidad y grupos de atención prioritaria.', 'Activo', '2026-07-16 12:36:38', '2026-07-16 12:36:38'),
	(48, 5, '5.7', 'Fortalecer la productividad laboral', 'Fortalecer la productividad laboral mediante procesos de capacitación continua, innovación y modernización de los procesos productivos.', 'Activo', '2026-07-16 12:36:38', '2026-07-16 12:36:38'),
	(49, 5, '5.8', 'Impulsar alianzas para el desarrollo económico y el empleo', 'Promover alianzas entre el sector público, privado, academia y sociedad civil para fomentar el empleo y el desarrollo económico sostenible.', 'Activo', '2026-07-16 12:36:38', '2026-07-16 12:36:38'),
	(50, 6, '6.1', 'Fortalecer la sostenibilidad macroeconómica', 'Fortalecer la sostenibilidad macroeconómica mediante una gestión fiscal responsable, eficiente y transparente que contribuya al desarrollo económico del país.', 'Activo', '2026-07-16 12:36:47', '2026-07-16 12:36:47'),
	(51, 6, '6.2', 'Fortalecer el sistema financiero nacional', 'Fortalecer el sistema financiero nacional promoviendo la estabilidad, la inclusión financiera y el acceso al crédito para los sectores productivos y la ciudadanía.', 'Activo', '2026-07-16 12:36:47', '2026-07-16 12:36:47'),
	(52, 6, '6.3', 'Optimizar la gestión de las finanzas públicas', 'Optimizar la gestión de las finanzas públicas mediante la eficiencia del gasto, la sostenibilidad fiscal y el fortalecimiento de los mecanismos de control y transparencia.', 'Activo', '2026-07-16 12:36:47', '2026-07-16 12:36:47'),
	(53, 6, '6.4', 'Fortalecer la administración tributaria y la recaudación fiscal', 'Fortalecer la administración tributaria para incrementar la recaudación, reducir la evasión y promover una cultura tributaria basada en la equidad y la eficiencia.', 'Activo', '2026-07-16 12:36:47', '2026-07-16 12:36:47'),
	(54, 7, '7.1', 'Promover el aprovechamiento sostenible de los recursos naturales', 'Promover el aprovechamiento sostenible de los recursos naturales mediante una gestión responsable que garantice su conservación y contribuya al desarrollo económico y social del país.', 'Activo', '2026-07-16 12:36:55', '2026-07-16 12:36:55'),
	(55, 7, '7.2', 'Fortalecer la conservación de la biodiversidad y los ecosistemas', 'Fortalecer la conservación, restauración y uso sostenible de la biodiversidad y de los ecosistemas estratégicos, promoviendo su protección para las generaciones presentes y futuras.', 'Activo', '2026-07-16 12:36:55', '2026-07-16 12:36:55'),
	(56, 7, '7.3', 'Impulsar la gestión integral del recurso hídrico', 'Impulsar la gestión integral, sostenible y eficiente del recurso hídrico para garantizar su disponibilidad, calidad y acceso para la población y los sectores productivos.', 'Activo', '2026-07-16 12:36:55', '2026-07-16 12:36:55'),
	(57, 7, '7.4', 'Fortalecer la adaptación y mitigación frente al cambio climático', 'Fortalecer las acciones de adaptación y mitigación frente al cambio climático mediante políticas públicas orientadas a reducir la vulnerabilidad ambiental y territorial.', 'Activo', '2026-07-16 12:36:55', '2026-07-16 12:36:55'),
	(58, 7, '7.5', 'Promover la gestión ambiental sostenible', 'Promover una gestión ambiental sostenible mediante el fortalecimiento de la gobernanza ambiental, el control de la contaminación y el uso responsable de los recursos naturales.', 'Activo', '2026-07-16 12:36:55', '2026-07-16 12:36:55'),
	(59, 8, '8.1', 'Fortalecer la infraestructura estratégica nacional', 'Fortalecer la infraestructura estratégica nacional mediante inversiones sostenibles que mejoren la competitividad, la integración territorial y el acceso a servicios públicos de calidad.', 'Activo', '2026-07-16 12:37:03', '2026-07-16 12:37:03'),
	(60, 8, '8.2', 'Impulsar la conectividad física y digital del país', 'Impulsar la conectividad física y digital mediante el desarrollo de infraestructura vial, portuaria, aeroportuaria y de telecomunicaciones para fortalecer el desarrollo nacional.', 'Activo', '2026-07-16 12:37:03', '2026-07-16 12:37:03'),
	(61, 8, '8.3', 'Garantizar el acceso sostenible a la energía', 'Garantizar el acceso sostenible, seguro y eficiente a la energía, promoviendo la diversificación de la matriz energética y el uso responsable de los recursos energéticos.', 'Activo', '2026-07-16 12:37:03', '2026-07-16 12:37:03'),
	(62, 8, '8.4', 'Promover el uso de energías renovables y la eficiencia energética', 'Promover el desarrollo de energías renovables y la eficiencia energética para fortalecer la seguridad energética y reducir los impactos ambientales.', 'Activo', '2026-07-16 12:37:03', '2026-07-16 12:37:03'),
	(63, 8, '8.5', 'Fortalecer la infraestructura para la movilidad y el transporte', 'Fortalecer la infraestructura para la movilidad y el transporte mediante sistemas seguros, eficientes, inclusivos y sostenibles que mejoren la integración territorial.', 'Activo', '2026-07-16 12:37:03', '2026-07-16 12:37:03'),
	(64, 8, '8.6', 'Impulsar la transformación digital y la innovación tecnológica', 'Impulsar la transformación digital del Estado y de los sectores productivos mediante el fortalecimiento de las tecnologías de la información y la innovación.', 'Activo', '2026-07-16 12:37:03', '2026-07-16 12:37:03'),
	(65, 8, '8.7', 'Fortalecer la planificación y gestión de la infraestructura pública', 'Fortalecer la planificación, construcción, mantenimiento y gestión eficiente de la infraestructura pública para garantizar servicios de calidad a la población.', 'Activo', '2026-07-16 12:37:03', '2026-07-16 12:37:03'),
	(66, 9, '9.1', 'Fortalecer la institucionalidad del Estado', 'Fortalecer la institucionalidad del Estado mediante una gestión pública eficiente, transparente, orientada a resultados y al servicio de la ciudadanía.', 'Activo', '2026-07-16 12:37:11', '2026-07-16 12:37:11'),
	(67, 9, '9.2', 'Impulsar la transparencia, la integridad pública y la participación ciudadana', 'Impulsar la transparencia, la integridad pública, la rendición de cuentas y la participación ciudadana como pilares del fortalecimiento democrático y de la confianza en las instituciones.', 'Activo', '2026-07-16 12:37:11', '2026-07-16 12:37:11'),
	(68, 9, '9.3', 'Fortalecer la transformación digital y la modernización del Estado', 'Fortalecer la transformación digital, la innovación y la modernización de la administración pública para mejorar la calidad, oportunidad y eficiencia de los servicios públicos.', 'Activo', '2026-07-16 12:37:11', '2026-07-16 12:37:11'),
	(69, 10, '10.1', 'Fortalecer la gestión integral de riesgos', 'Fortalecer la gestión integral de riesgos mediante acciones de prevención, mitigación, preparación, respuesta y recuperación frente a amenazas naturales y antrópicas, promoviendo territorios resilientes.', 'Activo', '2026-07-16 12:37:19', '2026-07-16 12:37:19'),
	(70, 10, '10.2', 'Fortalecer la resiliencia de la población y de la infraestructura estratégica', 'Fortalecer la resiliencia de la población, de las instituciones y de la infraestructura estratégica del país frente a eventos adversos, incorporando la gestión de riesgos en la planificación del desarrollo.', 'Activo', '2026-07-16 12:37:19', '2026-07-16 12:37:19');
